import java.util.*;
public class KPairs {
    public static List<List<Integer>> kSmallestPairs(int[] nums1, int[] nums2, int k){
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[0]+a[1]-b[0]-b[1]);
        List<List<Integer>> res=new ArrayList<>();
        for(int i=0;i<Math.min(k,nums1.length);i++)pq.offer(new int[]{nums1[i],nums2[0],0});
        while(k-->0&&!pq.isEmpty()){int[] top=pq.poll();res.add(Arrays.asList(top[0],top[1]));int j=top[2]+1;if(j<nums2.length)pq.offer(new int[]{top[0],nums2[j],j});}
        return res;
    }
    public static void main(String[] a){System.out.println(kSmallestPairs(new int[]{1,7,11},new int[]{2,4,6},3));System.out.println("[[1,2],[1,4],[1,6]] — push (nums1[i], nums2[0]) initially; expand by j++");}
}

import java.util.*;
public class LazyHeap {
    // Simulate: find max excluding deleted elements
    static PriorityQueue<Integer> pq=new PriorityQueue<>(Collections.reverseOrder());
    static Map<Integer,Integer> deleted=new HashMap<>();
    static void offer(int v){pq.offer(v);}
    static void delete(int v){deleted.merge(v,1,Integer::sum);}
    static int findMax(){while(!pq.isEmpty()&&deleted.getOrDefault(pq.peek(),0)>0){deleted.merge(pq.peek(),-1,Integer::sum);if(deleted.get(pq.peek())==0)deleted.remove(pq.peek());pq.poll();}return pq.isEmpty()?-1:pq.peek();}
    public static void main(String[] a){offer(5);offer(3);offer(8);offer(1);delete(8);delete(5);System.out.println(findMax());System.out.println("3 — lazy deletion: mark removed, skip on poll. O(log n) amortized.");}
}

import java.util.*;
public class KthMatrix2 {
    public static int kthSmallest(int[][] matrix, int k){
        int n=matrix.length;
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[0]-b[0]);
        for(int i=0;i<n;i++)pq.offer(new int[]{matrix[i][0],i,0});
        int res=0;
        for(int i=0;i<k;i++){int[] top=pq.poll();res=top[0];int r=top[1],c=top[2];if(c+1<n)pq.offer(new int[]{matrix[r][c+1],r,c+1});}
        return res;
    }
    public static void main(String[] a){int[][] m={{1,5,9},{10,11,13},{12,13,15}};System.out.println(kthSmallest(m,8));System.out.println(kthSmallest(m,3));System.out.println("O(k log n) min-heap. O(n log n) binary search alternative.");}
}

import java.util.*;
public class MaxCPU {
    public static int findMaxCPULoad(int[][] jobs){
        Arrays.sort(jobs,(a,b)->a[0]-b[0]);
        PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[1]-b[1]); // min-heap by end
        int maxLoad=0,curLoad=0;
        for(int[] job:jobs){
            while(!pq.isEmpty()&&pq.peek()[1]<=job[0]){curLoad-=pq.poll()[2];}
            pq.offer(job);curLoad+=job[2];maxLoad=Math.max(maxLoad,curLoad);}
        return maxLoad;
    }
    public static void main(String[] a){System.out.println(findMaxCPULoad(new int[][]{{1,4,3},{2,5,4},{7,9,6}}));System.out.println(findMaxCPULoad(new int[][]{{6,7,10},{2,4,11},{8,12,15}}));System.out.println("O(n log n) — same pattern as Meeting Rooms II but track load sum");}
}

import java.util.*;
public class KthMethods {
    static int heapMethod(int[] nums,int k){PriorityQueue<Integer> pq=new PriorityQueue<>();for(int n:nums){pq.offer(n);if(pq.size()>k)pq.poll();}return pq.peek();}
    static int quickSelect(int[] nums,int k){return qs(nums,0,nums.length-1,nums.length-k);}
    static int qs(int[] a,int lo,int hi,int k){if(lo>=hi)return a[lo];int pivot=partition(a,lo,hi);if(pivot==k)return a[pivot];return pivot<k?qs(a,pivot+1,hi,k):qs(a,lo,pivot-1,k);}
    static int partition(int[] a,int lo,int hi){int pivot=a[hi],i=lo;for(int j=lo;j<hi;j++)if(a[j]<=pivot){int t=a[i];a[i]=a[j];a[j]=t;i++;}int t=a[i];a[i]=a[hi];a[hi]=t;return i;}
    public static void main(String[] a){int[] nums={3,2,1,5,6,4};System.out.println(heapMethod(nums.clone(),2));System.out.println(quickSelect(nums.clone(),2));System.out.println("Heap: O(n log k). QuickSelect: O(n) avg O(n²) worst.");}
}

import java.util.*;
public class EmpFreeTime {
    static class Interval{int start,end;Interval(int s,int e){start=s;end=e;}}
    public static List<Interval> employeeFreeTime(List<List<Interval>> schedule){
        List<Interval> all=new ArrayList<>();for(var s:schedule)all.addAll(s);all.sort((a,b)->a.start-b.start);List<Interval> res=new ArrayList<>();int end=all.get(0).end;for(var iv:all){if(iv.start>end)res.add(new Interval(end,iv.start));end=Math.max(end,iv.end);}return res;
    }
    public static void main(String[] a){List<List<Interval>> s=new ArrayList<>();s.add(Arrays.asList(new Interval(1,3),new Interval(6,7)));s.add(Arrays.asList(new Interval(2,4)));s.add(Arrays.asList(new Interval(2,5),new Interval(9,12)));List<Interval> free=employeeFreeTime(s);for(Interval iv:free)System.out.print("["+iv.start+","+iv.end+"] ");System.out.println();System.out.println("Sort all intervals, find gaps where current.start > max end so far");}
}

import java.util.*;
public class ConnectRopes {
    public static long minCost(int[] ropes){PriorityQueue<Long> pq=new PriorityQueue<>();for(int r:ropes)pq.offer((long)r);long total=0;while(pq.size()>1){long a=pq.poll(),b=pq.poll();total+=a+b;pq.offer(a+b);}return total;}
    public static void main(String[] a){System.out.println(minCost(new int[]{4,3,2,6}));System.out.println(minCost(new int[]{1,2,3,4,5}));System.out.println("O(n log n) — greedy: always combine two smallest. Huffman encoding base.");}
}

import java.util.*;
public class EventSim {
    record Event(int time, String name) implements Comparable<Event>{public int compareTo(Event o){return Integer.compare(time,o.time);}}
    public static void main(String[] a){PriorityQueue<Event> pq=new PriorityQueue<>();pq.offer(new Event(5,"payment_due"));pq.offer(new Event(1,"user_login"));pq.offer(new Event(3,"api_call"));pq.offer(new Event(2,"db_query"));System.out.println("Event processing order:");while(!pq.isEmpty()){Event e=pq.poll();System.out.println("t="+e.time()+": "+e.name());}System.out.println("Min-heap as event priority queue. O(log n) schedule/process.");}
}

import java.util.*;
public class KWaySynth {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode mergeK(ListNode[] lists){PriorityQueue<ListNode> pq=new PriorityQueue<>((a,b)->a.val-b.val);for(ListNode l:lists)if(l!=null)pq.offer(l);ListNode d=new ListNode(0),c=d;while(!pq.isEmpty()){c.next=pq.poll();c=c.next;if(c.next!=null)pq.offer(c.next);}return d.next;}
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    static int kthSmallest(int[][] m,int k){int n=m.length;PriorityQueue<int[]> pq=new PriorityQueue<>((a,b)->a[0]-b[0]);for(int i=0;i<n;i++)pq.offer(new int[]{m[i][0],i,0});int res=0;for(int i=0;i<k;i++){int[] top=pq.poll();res=top[0];int r=top[1],c=top[2];if(c+1<n)pq.offer(new int[]{m[r][c+1],r,c+1});}return res;}
    public static void main(String[] a){System.out.println(str(mergeK(new ListNode[]{of(1,4,5),of(1,3,4),of(2,6)})));System.out.println(kthSmallest(new int[][]{{1,5,9},{10,11,13},{12,13,15}},8));boolean ok=str(mergeK(new ListNode[]{of(1,4,5),of(1,3,4),of(2,6)})).equals("1-1-2-3-4-4-5-6")&&kthSmallest(new int[][]{{1,5,9},{10,11,13},{12,13,15}},8)==13;System.out.println("All pass: "+ok);}
}

import java.util.*;
public class M36Final {
    static int kthL(int[] n,int k){PriorityQueue<Integer> pq=new PriorityQueue<>();for(int x:n){pq.offer(x);if(pq.size()>k)pq.poll();}return pq.peek();}
    static int[] topK(int[] n,int k){Map<Integer,Integer> f=new HashMap<>();for(int x:n)f.merge(x,1,Integer::sum);PriorityQueue<Integer> pq=new PriorityQueue<>(Comparator.comparingInt(f::get));for(int x:f.keySet()){pq.offer(x);if(pq.size()>k)pq.poll();}int[]r=new int[k];for(int i=k-1;i>=0;i--)r[i]=pq.poll();return r;}
    static int meetR(int[][] ivs){Arrays.sort(ivs,(a,b)->a[0]-b[0]);PriorityQueue<Integer> pq=new PriorityQueue<>();for(int[]iv:ivs){if(!pq.isEmpty()&&pq.peek()<=iv[0])pq.poll();pq.offer(iv[1]);}return pq.size();}
    static int taskS(char[] t,int n){int[]c=new int[26];for(char x:t)c[x-'A']++;int m=0;for(int x:c)m=Math.max(m,x);int cnt=0;for(int x:c)if(x==m)cnt++;return Math.max((m-1)*(n+1)+cnt,t.length);}
    public static void main(String[] a){System.out.println("kthL="+kthL(new int[]{3,2,1,5,6,4},2));System.out.println("topK="+Arrays.toString(topK(new int[]{1,1,1,2,2,3},2)));System.out.println("meetR="+meetR(new int[][]{{0,30},{5,10},{15,20}}));System.out.println("taskS="+taskS(new char[]{'A','A','A','B','B','B'},2));boolean ok=kthL(new int[]{3,2,1,5,6,4},2)==5&&meetR(new int[][]{{0,30},{5,10},{15,20}})==2&&taskS(new char[]{'A','A','A','B','B','B'},2)==8;System.out.println("All pass: "+ok);}
}
